#include <bits/stdc++.h>
using namespace std;
int main(){
    int a[104][104]={0};
    int n,m,k,sum=0;
    cin>>n>>m>>k;
    int x,y;
    for(int i=1;i<=m;i++){
        cin>>x>>y;
        x++;y++;
        for(int j=x-2;j<=x+2;j++)a[j][y]=1;
        for(int j=y-2;j<=y+2;j++)a[x][j]=1;
        a[x-1][y-1]=a[x-1][y+1]=a[x+1][y+1]=a[x+1][y-1]=1;
    }
    for(int i=1;i<=k;i++){
        cin>>x>>y;
        x++;y++;
        for(int j=x-2;j<=x+2;j++)
            for(int z=y-2;z<=y+2;z++)a[j][z]=1;
    }
    for(int i=2;i<=n+1;i++)
        for(int j=2;j<=n+1;j++)if(!a[i][j])sum++;
    cout<<sum;
    return 0;
}
